import{_ as e,o as i,c as t,a2 as s}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"部署说明（GitHub Pages + 自定义域名）","description":"","frontmatter":{},"headers":[],"relativePath":"DEPLOY.md","filePath":"DEPLOY.md","lastUpdated":1783292109000}'),o={name:"DEPLOY.md"};function d(n,a,l,r,h,c){return i(),t("div",null,[...a[0]||(a[0]=[s(`<h1 id="部署说明-github-pages-自定义域名" tabindex="-1">部署说明（GitHub Pages + 自定义域名） <a class="header-anchor" href="#部署说明-github-pages-自定义域名" aria-label="Permalink to &quot;部署说明（GitHub Pages + 自定义域名）&quot;">​</a></h1><p>本手册用 <strong>VitePress</strong> 构建，通过 <strong>GitHub Actions</strong> 自动部署到 <strong>GitHub Pages</strong>，绑定自定义域名 <strong>wiki.freedomport.cc</strong>。全程免费。</p><h2 id="自动部署-已配置" tabindex="-1">自动部署（已配置） <a class="header-anchor" href="#自动部署-已配置" aria-label="Permalink to &quot;自动部署（已配置）&quot;">​</a></h2><ul><li>每次 <code>git push</code> 到 <code>main</code>，<code>.github/workflows/deploy.yml</code> 会自动构建并发布</li><li>构建产物是 <code>.vitepress/dist</code>，<code>public/CNAME</code> 保证自定义域名在每次部署后保留</li></ul><h2 id="一次性开启步骤" tabindex="-1">一次性开启步骤 <a class="header-anchor" href="#一次性开启步骤" aria-label="Permalink to &quot;一次性开启步骤&quot;">​</a></h2><h3 id="_1-启用-github-pages-actions-来源" tabindex="-1">1. 启用 GitHub Pages（Actions 来源） <a class="header-anchor" href="#_1-启用-github-pages-actions-来源" aria-label="Permalink to &quot;1. 启用 GitHub Pages（Actions 来源）&quot;">​</a></h3><p>仓库 → Settings → Pages → Build and deployment → Source 选 <strong>GitHub Actions</strong>。</p><h3 id="_2-cloudflare-添加-dns-记录" tabindex="-1">2. Cloudflare 添加 DNS 记录 <a class="header-anchor" href="#_2-cloudflare-添加-dns-记录" aria-label="Permalink to &quot;2. Cloudflare 添加 DNS 记录&quot;">​</a></h3><p>到 Cloudflare 的 <code>freedomport.cc</code> DNS 面板添加：</p><table tabindex="0"><thead><tr><th>类型</th><th>名称</th><th>目标</th><th>代理状态</th></tr></thead><tbody><tr><td>CNAME</td><td><code>wiki</code></td><td><code>skxxxkx666.github.io</code></td><td>橙云（推荐，改善大陆访问 + 免费 SSL）</td></tr></tbody></table><p>若橙云下证书握手异常，先切 DNS only（灰云）等 GitHub 侧签发证书后再开橙云。</p><h3 id="_3-github-侧确认自定义域名" tabindex="-1">3. GitHub 侧确认自定义域名 <a class="header-anchor" href="#_3-github-侧确认自定义域名" aria-label="Permalink to &quot;3. GitHub 侧确认自定义域名&quot;">​</a></h3><p>仓库 → Settings → Pages → Custom domain 填 <code>wiki.freedomport.cc</code> → Save，勾选 Enforce HTTPS。</p><h2 id="本地开发" tabindex="-1">本地开发 <a class="header-anchor" href="#本地开发" aria-label="Permalink to &quot;本地开发&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wiki</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # 本地预览</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 构建到 .vitepress/dist</span></span></code></pre></div><h2 id="日常维护" tabindex="-1">日常维护 <a class="header-anchor" href="#日常维护" aria-label="Permalink to &quot;日常维护&quot;">​</a></h2><ul><li>改文档：编辑对应 <code>.md</code> → commit → push，Actions 自动重新发布</li><li>加页面：新建 <code>.md</code> 后在 <code>.vitepress/config.mts</code> 的 <code>sidebar</code> 里登记</li><li>加图片：放在 <code>.md</code> 同目录，用相对路径 <code>./xxx.png</code> 引用</li></ul><h2 id="写作规范" tabindex="-1">写作规范 <a class="header-anchor" href="#写作规范" aria-label="Permalink to &quot;写作规范&quot;">​</a></h2><ul><li><strong>标题和正文不使用 emoji</strong>，保持专业克制的排版</li><li>推荐标记用文字（&quot;推荐&quot;）而不是符号</li><li>提示用 <code>::: info</code> / <code>::: warning</code> / <code>::: danger</code> 容器</li></ul>`,19)])])}const g=e(o,[["render",d]]);export{u as __pageData,g as default};
